cd "C:/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad" && python - <<'EOF'
import csv
rows=list(csv.DictReader(open('sqp_digests/sqp_brand_monthly.csv')))
core={r['month']:r for r in rows if r['uni']=='core'}
def s(months,f): return sum(float(core[m][f]) for m in months)
m25=['2025-02','2025-03','2025-04','2025-05','2025-06']
m26=['2026-02','2026-03','2026-04','2026-05','2026-06']
print("=== SQP core, weighted funnel share (my/mkt), Feb-Jun YoY ===")
for stage,(mine,mkt) in {'imp':('my_imp','mkt_imp'),'clk':('my_clk','mkt_clk'),'atc':('my_atc','mkt_atc'),'ord':('my_ord','mkt_ord')}.items():
    sh25=s(m25,mine)/s(m25,mkt)*100; sh26=s(m26,mine)/s(m26,mkt)*100
    print(f"  {stage}_share: {sh25:.2f}% -> {sh26:.2f}%  ({sh26-sh25:+.2f}pp)")
print("  my_ord units:", int(s(m25,'my_ord')),"->",int(s(m26,'my_ord')), f"({s(m26,'my_ord')/s(m25,'my_ord')-1:+.1%})")
cvr25=s(m25,'mkt_ord')/s(m25,'mkt_sv')*100; cvr26=s(m26,'mkt_ord')/s(m26,'mkt_sv')*100
print(f"  MARKET CVR: {cvr25:.2f}% -> {cvr26:.2f}%  ({cvr26-cvr25:+.2f}pp) [market-level SQP]")

sm=list(csv.DictReader(open('lingxing_snapshot/store_monthly.csv')))
allrows={r['month']:r for r in sm if r['sid']=='ALL'}
def sv(months,f): return sum(float(allrows[m][f]) for m in months)
print("\n=== Lingxing brand-merged (ALL), Feb-Jun YoY ===")
v25=sv(m25,'volume'); v26=sv(m26,'volume'); g25=sv(m25,'sales_amount_gross_usd'); g26=sv(m26,'sales_amount_gross_usd')
print(f"  volume: {int(v25)} -> {int(v26)}  ({v26/v25-1:+.1%})")
print(f"  gross$: {g25:,.0f} -> {g26:,.0f}  ({g26/g25-1:+.1%})")
print(f"  ASP: ${g25/v25:.0f} -> ${g26/v26:.0f}  ({(g26/v26)/(g25/v25)-1:+.1%})")

am=list(csv.DictReader(open('lingxing_snapshot/asin_monthly.csv')))
main5={'B0DHPN1DMJ','B0CR1R7FKP','B0CLLT85Y6','B0DCZQX11P','B0FNCQW2K3'}
def agg(months):
    vol=net=sess=0
    for r in am:
        if r['sid']=='7481' and r['asin'] in main5 and r['month'] in months:
            vol+=float(r['volume']); net+=float(r['net_amount']); sess+=float(r['sessions_total'])
    return vol,net,sess
v25,n25,se25=agg(m25); v26,n26,se26=agg(m26)
print("\n=== Lingxing 5-main ASIN (7481), Feb-Jun YoY ===")
print(f"  volume: {int(v25)} -> {int(v26)}  ({v26/v25-1:+.1%})")
print(f"  net$:   {n25:,.0f} -> {n26:,.0f}  ({n26/n25-1:+.1%})")
print(f"  self CVR (vol/sessions): {v25/se25*100:.2f}% -> {v26/se26*100:.2f}%  ({(v26/se26-v25/se25)*100:+.2f}pp) [self-funnel Lingxing]")

pf=list(csv.DictReader(open('sqp_digests/profit_op_monthly.csv')))
def wm(op,months):
    gp=sum(float(r['gross_profit']) for r in pf if r['operator']==op and r['month'] in months)
    sa=sum(float(r['sales']) for r in pf if r['operator']==op and r['month'] in months)
    return gp/sa*100
print("\n=== Profit operator margins (Lingxing) ===")
for op in ['赵健宏','毛香明']:
    print(f"  {op}: Mar-May26={wm(op,['2026-03','2026-04','2026-05']):.1f}%  vs same-offseason Aug-Oct25={wm(op,['2025-08','2025-09','2025-10']):.1f}%")

print("\n=== Net ASP 2026 (net/vol) ===")
for asin,name,lp in [('B0DHPN1DMJ','S2',349.99),('B0CR1R7FKP','X2',449.99)]:
    print(f"  {name} (list ${lp}):", end=" ")
    for m in ['2026-01','2026-02','2026-03','2026-04','2026-05','2026-06']:
        for r in am:
            if r['sid']=='7481' and r['asin']==asin and r['month']==m and float(r['volume'])>0:
                print(f"{m[5:]}=${float(r['net_amount'])/float(r['volume']):.0f}",end=" ")
    print()
print("\n=== Return rate 2026 ===")
for asin,name in [('B0DHPN1DMJ','S2'),('B0CR1R7FKP','X2')]:
    print(f"  {name}:", end=" ")
    for m in ['2026-01','2026-02','2026-03','2026-04','2026-05','2026-06']:
        for r in am:
            if r['sid']=='7481' and r['asin']==asin and r['month']==m:
                print(f"{m[5:]}={float(r['return_rate'])*100:.0f}%",end=" ")
    print()
EOF

